import React from 'react';

const leaderProfiles = [
  { 
    desc: 'Driving the vision for Hudson, Mayank combines deep IT consultancy with strategic manpower leadership. His focus is on pioneering industry-specific tech and sourcing.Driving the vision for Hudson, Mayank combines deep IT consultancy with strategic manpower leadership. His focus is on pioneering industry-specific tech and sourcing.Driving the vision for Hudson, Mayank combines deep IT consultancy with strategic manpower leadership. His focus is on pioneering industry-specific tech and sourcing. Driving the vision for Hudson, Mayank combines deep IT consultancy with strategic manpower leadership. His focus is on pioneering industry-specific tech and sourcing.',
    icon: '👤'
  },
];

const Electronics = () => {
  return (
    <div className="bg-white antialiased w-full">

      {/* 1. FULL WIDTH HEADER */}
      <section className="pt-32 pb-20 px-6 md:px-16 w-full bg-gradient-to-r from-[#1F140F] to-[#2E1A11] text-white">
        <div className="w-full">
          <h1 className="text-5xl md:text-7xl font-black tracking-tighter mb-6">
            Electrical <span className="text-orange-400">Solutions</span>
          </h1>
          <p className="text-orange-100 text-lg md:text-xl font-light max-w-3xl leading-relaxed">
            Expert staffing for power grids, industrial wiring, and renewable energy projects worldwide.
          </p>
        </div>
      </section>

      {/* 2. FULL WIDTH PROFILE SECTION (No Max-Width) */}
   <section className="w-full bg-white border-t border-gray-100">
  {/* Header Section */}
  <div className="py-16 px-6 md:px-16 w-full bg-gray-50">
    <h2 className="text-5xl font-black text-gray-900 tracking-tighter">
      Leadership <span className="text-orange-600">Spotlight</span>
    </h2>
    <div className="h-1.5 w-24 bg-orange-500 mt-4 rounded-full"></div>
  </div>

  {/* Full Width Stacked Profiles */}
  <div className="w-full flex flex-col"> {/* flex-col se profiles ek ke niche ek aayenge */}
    {leaderProfiles.map((leader, index) => (
      <div 
        key={index} 
        className={`w-full px-6 md:px-16 py-16 flex flex-col md:flex-row items-center gap-12 border-b border-gray-100 last:border-b-0 hover:bg-orange-50/30 transition-colors`}
      >
        {/* Left Side: Avatar/Icon */}
        <div className="flex-shrink-0">
          <div className="h-40 w-40 bg-white border-2 border-orange-100 rounded-full flex items-center justify-center text-7xl text-orange-500 shadow-xl overflow-hidden relative group">
            {/* Subtle decorative ring */}
            <div className="absolute inset-0 border-4 border-dashed border-orange-200 rounded-full animate-[spin_10s_linear_infinite] opacity-0 group-hover:opacity-100 transition-opacity"></div>
            {leader.icon || '👤'}
          </div>
        </div>

        {/* Right Side: Content (Taking full remaining width) */}
        <div className="flex-grow">


          <div className="relative">
            {/* Quote design */}
            <p className="text-gray-700 text-xl leading-relaxed italic max-w-5xl">
              "{leader.desc}"
            </p>
            <div className="mt-8 flex gap-4">
               <button className="bg-gray-900 text-white px-6 py-2 rounded-full font-bold text-sm hover:bg-orange-600 transition-all">
                 View LinkedIn Profile
               </button>
            </div>
          </div>
        </div>
      </div>
    ))}
  </div>
</section>

      {/* 3. FULL WIDTH CAREER BANNER */}
      <section className="py-24 px-6 md:px-16 w-full bg-white">
        <div className="w-full bg-gradient-to-r from-orange-500 to-orange-600 rounded-[3rem] p-12 md:p-20 flex flex-col md:flex-row items-center justify-between text-white shadow-2xl shadow-orange-100">
          <div className="md:w-2/3">
            <h2 className="text-4xl md:text-6xl font-bold mb-6 tracking-tighter leading-tight">
              Start Your Career <br /> With Hudson Today
            </h2>
            <p className="text-orange-50 text-xl mb-10 max-w-xl">
              Join our global network of engineers and technicians. We're hiring for major electrical projects.
            </p>
            <button className="bg-white text-orange-600 px-12 py-5 rounded-full font-bold text-xl hover:scale-105 transition-transform shadow-xl">
              Apply Now
            </button>
          </div>
          <div className="hidden md:flex md:w-1/3 justify-end">
            <div className="h-64 w-64 border-4 border-orange-400/30 rounded-full flex items-center justify-center animate-pulse">
               <span className="text-8xl opacity-20">⚡</span>
            </div>
          </div>
        </div>
      </section>

    </div>
  );
};

export default Electronics;
